package com.hospital.management.controller.prescription;import com.hospital.management.model.Prescription;import com.hospital.management.service.*;import com.hospital.management.service.impl.PrescriptionServiceImpl;import javax.servlet.*;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.IOException;@WebServlet("/prescriptions/view")public class PrescriptionViewServlet extends HttpServlet {private final PrescriptionService service;public PrescriptionViewServlet(){this(new PrescriptionServiceImpl());}public PrescriptionViewServlet(PrescriptionService s){service=s;}protected void doGet(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{Long id=PrescriptionRequest.id(q.getParameter("id"));Prescription p=id==null?null:service.getPrescription(id,PrescriptionRequest.user(q)).orElse(null);if(p==null){r.sendError(404);return;}q.setAttribute("prescription",p);q.getRequestDispatcher("/WEB-INF/views/prescriptions/view.jsp").forward(q,r);}}
